 1	import React, { FC, memo, useMemo, useState } from 'react';
 2	
 3	import {
 4	  FilterSidePanelCategory,
 5	  FilterSidePanelCategoryItem,
 6	} from '@patternfly/react-catalog-view-extension';
 7	import { Split, SplitItem, Title } from '@patternfly/react-core';
 8	import { AngleDownIcon, AngleRightIcon } from '@patternfly/react-icons';
 9	
10	import './TemplatesCatalogFiltersGroup.scss';
11	
12	export const TemplatesCatalogFiltersGroup: FC<{
13	  defaultExpanded?: boolean;
14	  filters: {
15	    count?: number;
16	    label?: string;
17	    value: string;
18	  }[];
19	  groupKey: string;
20	  groupLabel?: string;
21	  onFilterClick: (type: string, value: string) => void;
22	  pickedFilters: Set<string>;
23	}> = memo(
24	  ({ defaultExpanded = true, filters, groupKey, groupLabel, onFilterClick, pickedFilters }) => {
25	    const [isExpanded, setIsExpanded] = useState(defaultExpanded);
26	
27	    const memoFilters = useMemo(
28	      () =>
29	        filters.map(({ count, label, value }) => (
30	          <FilterSidePanelCategoryItem
31	            checked={pickedFilters?.has(value)}
32	            count={count}
33	            data-test-id={`${groupKey}-${label}`}
34	            key={`${groupKey}-${label}`}
35	            onClick={() => onFilterClick(groupKey, value)}
36	          >
37	            {label ?? value}
38	          </FilterSidePanelCategoryItem>
39	        )),
40	      [filters, pickedFilters, onFilterClick, groupKey],
41	    );
42	
43	    return (
44	      <FilterSidePanelCategory data-test-id={`filter-category-${groupLabel}`}>
45	        {groupLabel && (
46	          <Split className="vm-filter-group-header" onClick={() => setIsExpanded(!isExpanded)}>
47	            <SplitItem>
48	              {isExpanded ? (
49	                <AngleDownIcon className="pf-v5-c-dropdown__toggle-icon" />
50	              ) : (
51	                <AngleRightIcon className="pf-v5-c-dropdown__toggle-icon" />
52	              )}
53	            </SplitItem>
54	            <SplitItem className="vm-filter-group-title" isFilled>
55	              <Title headingLevel="h5" size="md">
56	                {groupLabel}
57	              </Title>
58	            </SplitItem>
59	          </Split>
60	        )}
61	        {isExpanded && memoFilters}
62	      </FilterSidePanelCategory>
63	    );
64	  },
65	);
66	TemplatesCatalogFiltersGroup.displayName = 'TemplateFilterGroup';

